patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index b9ce20ebd3e6..6caa625b5ef2 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -563,7 +563,12 @@ static ExtractElementInst *translateExtract(ExtractElementInst *ExtElt,

   Value *Shuf = createShiftShuffle(X, cast<ConstantInt>(C)->getZExtValue(),
                                    NewIndex, Builder);
-  return cast<ExtractElementInst>(Builder.CreateExtractElement(Shuf, NewIndex));
+  Value *NewExtract = Builder.CreateExtractElement(Shuf, NewIndex);
+  // If the extract was constant-folded, return nullptr as no new instruction
+  // was created. This is consistent with the handling of constant inputs above.
+  if (!isa<ExtractElementInst>(NewExtract))
+    return nullptr;
+  return cast<ExtractElementInst>(NewExtract);
 }

 /// Try to reduce extract element costs by converting scalar compares to vector

